from flask import Flask, request, jsonify
import redis

app = Flask(__name__)

# Redis connection settings
redis_config = {
    'host': 'localhost',
    'port': 6379,
    'db': 0
}

# Create a Redis client instance
r = redis.Redis(**redis_config)

@app.route('/execute', methods=['POST'])
def execute_redis_command():
    if request.method == 'POST':
        command = request.args.get('command')
        
        # Validate the input to prevent SQL injection-like attacks
        if not isinstance(command, str) or len(command.split()) > 1:
            return jsonify({'error': 'Invalid Redis command'}), 400
        
        try:
            result = r.execute_command(command)
            return jsonify({'result': result}), 200
        except redis.exceptions.RedisError as e:
            return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)